let activeFilter = 'ALL';
function renderGlossary(data) {
  const cats = ['ALL', ...new Set(glossaryData.map(g => g.cat))];
  document.getElementById('glossaryFilter').innerHTML = cats.map(c =>
    `<button class="filter-btn ${c===activeFilter?'active':''}" onclick="setFilter('${c}')">${c}</button>`).join('');
  document.getElementById('glossaryGrid').innerHTML = data.map(g => `
    <div class="glossary-card">
      <div class="g-term">${g.term} <span class="g-en">${g.en}</span>
        <span class="g-category tag ${g.catColor}" style="margin-left:auto">${g.cat}</span>
      </div>
      <div class="g-desc">${g.desc}</div>
      ${g.formula ? `<div class="g-formula">= ${g.formula}</div>` : ''}
    </div>`).join('');
}

function setFilter(cat) {
  activeFilter = cat;
  const q = document.getElementById('glossarySearch').value.toLowerCase();
  filterGlossaryWith(q);
}

function filterGlossary() {
  const q = document.getElementById('glossarySearch').value.toLowerCase();
  filterGlossaryWith(q);
}

function filterGlossaryWith(q) {
  let data = glossaryData;
  if (activeFilter !== 'ALL') data = data.filter(g => g.cat === activeFilter);
  if (q) data = data.filter(g => g.term.toLowerCase().includes(q) || g.en.toLowerCase().includes(q) || g.desc.toLowerCase().includes(q));
  renderGlossary(data);
}

