function renderSpecs() {
  document.getElementById('specGrid').innerHTML = specData.map(s => `
    <div class="spec-card">
      <div class="spec-header" style="background:${s.bg}">
        <div class="spec-icon" style="background:${s.bg}">${s.icon}</div>
        <div><div class="spec-name">${s.name}</div><div class="spec-tagline">${s.tagline}</div></div>
      </div>
      <div class="spec-body">
        ${s.rows.map(r=>`<div class="spec-row"><span class="spec-key">${r[0]}</span><span class="spec-val">${r[1]}</span></div>`).join('')}
      </div>
    </div>`).join('');
}

