// ─── Profile System ───
function editProfileName() {
  const current = localStorage.getItem('internName') || '';
  let ov = document.getElementById('nameModal');
  if (!ov) {
    ov = document.createElement('div');
    ov.id = 'nameModal'; ov.className = 'name-modal-overlay';
    ov.innerHTML =
      '<div class="name-modal" role="dialog" aria-modal="true" aria-label="이름 설정">' +
      '<div class="nm-title">이름 설정</div>' +
      '<div class="nm-sub">사이드바와 인사말에 표시됩니다</div>' +
      '<input id="nmInput" class="input" type="text" maxlength="20" placeholder="예: 홍길동, 제이콥">' +
      '<div class="nm-btns"><button type="button" class="btn btn-ghost btn-sm" onclick="closeNameModal()">취소</button>' +
      '<button type="button" class="btn btn-primary btn-sm" onclick="saveProfileName()">저장</button></div></div>';
    document.body.appendChild(ov);
    ov.addEventListener('click', e => { if (e.target === ov) closeNameModal(); });
    ov.querySelector('#nmInput').addEventListener('keydown', e => {
      if (e.key === 'Enter') { e.preventDefault(); saveProfileName(); }
      else if (e.key === 'Escape') { e.preventDefault(); closeNameModal(); }
    });
  }
  const inp = ov.querySelector('#nmInput');
  inp.value = current;
  ov.classList.add('open');
  setTimeout(() => { inp.focus(); inp.select(); }, 30);
}
function saveProfileName() {
  const v = (document.getElementById('nmInput').value || '').trim();
  if (v) { try { localStorage.setItem('internName', v); } catch (_) {} initProfile(); }
  closeNameModal();
}
function closeNameModal() {
  const ov = document.getElementById('nameModal');
  if (ov) ov.classList.remove('open');
}
function initProfile() {
  const name = localStorage.getItem('internName');
  const p = document.getElementById('profileName');
  if (!p) return;
  if (name) {
    p.innerHTML = '<span style="color:var(--primary)"></span> 마케터 님 ✏️';
    p.firstChild.textContent = name; // 이름은 textContent로 안전하게 삽입
  } else {
    p.textContent = '새내기 인턴 님 ✏️';
  }
}

// ─── Glossary Tooltip System ───
function applyTooltips(textStr) {
  if (!textStr) return "";
  const sorted = [...glossaryData].sort((a, b) => b.term.length - a.term.length);
  // 용어 → 항목 매핑(긴 용어 우선). 대소문자 무시 매칭을 위해 소문자 키 사용
  const map = {};
  sorted.forEach(it => { const k = it.term.toLowerCase(); if (!(k in map)) map[k] = it; });
  const alt = sorted.map(it => it.term.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&')).join('|');
  if (!alt) return String(textStr);
  const re = new RegExp(alt, 'gi');
  // 핵심: 원본 텍스트를 '한 번만' 스캔한다.
  // (이전 구현은 용어마다 누적 문자열을 재스캔해, 이미 삽입된 말풍선 설명 안의
  //  용어까지 다시 감싸 중첩 툴팁을 만들었음 — fixed 전환 후 말풍선이 겹쳐 떴다.)
  // 실제 HTML 태그(<a>, <br> 등)만 분리해 보존하고, 텍스트 조각만 처리한다.
  // 부등호("노출 < 클릭")는 태그가 아니므로 그대로 둔다.
  const parts = String(textStr).split(/(<\/?[a-zA-Z][^>]*>)/);
  for (let i = 0; i < parts.length; i++) {
    if (i % 2 === 1) continue; // 홀수 인덱스 = 태그, 건드리지 않음
    parts[i] = parts[i].replace(re, (match) => {
      const it = map[match.toLowerCase()];
      if (!it) return match;
      return `<span class="tip-trigger">${match}<span class="gloss-pop"><strong>${it.term}</strong>${it.desc}${it.formula ? '<br><br>💡 공식: ' + it.formula : ''}</span></span>`;
    });
  }
  return parts.join('');
}

